87	  it.todo("dragon-material sword ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
88	  it.todo("dragon-material sword ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
89	  it.todo("steel sword ench 9, damage 1000 G — payout 400 G (50% then deductible)");
90	
91	  // Claims — multiple damages
